import {
  HTMLAttributes,
  useEffect,
  useMemo,
  useRef,
  useState,
} from 'preact/compat';
import {
  Container,
  ResolveImageUrlOptions,
  Slot,
  SlotProps,
} from '@adobe-commerce/elsie/lib';

import { Image, ImageProps } from '@adobe-commerce/elsie/components';
import { events } from '@adobe-commerce/event-bus';
import { ProductModel } from '@/pdp/data/models/product-model';
import { getFetchedProductData } from '@/pdp/api';
import { useText } from '@adobe-commerce/elsie/i18n';
import { Carousel, Overlay, Zoom } from '@/pdp/components';
import {
  isDirectVideoFile,
  getEmbedUrl,
  getVideoPreviewUrl,
  getVideoMimeType,
} from '@/pdp/lib/videoUtils';
import { usePreloadImages } from '@/pdp/lib/usePreloadImages';
import '@/pdp/containers/ProductGallery/ProductGallery.css';

// Total time we hold the pending layer before promoting it. Must exceed the
// CSS transition duration in ProductGallery.css (currently 180ms). If you
// change one, update the other.
const CROSSFADE_MS = 200;

type DefaultSlotContext = {
  data: ProductModel | null;
};

type VideosProp = boolean | { position: 'first' | 'last' };

export interface ProductGalleryProps
  extends Omit<HTMLAttributes<HTMLDivElement>, 'controls'> {
  scope?: string;
  controls?: 'thumbnailsRow' | 'thumbnailsColumn' | 'dots' | null;
  loop?: boolean;
  peak?: boolean;
  gap?: 'small' | 'medium' | 'large' | null;
  arrows?: boolean;
  arrowsOnMainImage?: boolean;
  imageParams?: ResolveImageUrlOptions;
  thumbnailParams?: ResolveImageUrlOptions;
  zoom?: { closeButton: boolean } | boolean;
  videos?: VideosProp;
  slots?: {
    CarouselThumbnail?: SlotProps<
      DefaultSlotContext & {
        defaultImageProps: ImageProps;
        mediaType?: 'image' | 'video';
        previewUrl?: string;
      }
    >;
    CarouselMainImage?: SlotProps<
      DefaultSlotContext & {
        defaultImageProps: ImageProps;
        mediaType?: 'image' | 'video';
        previewUrl?: string;
      }
    >;
  };
}

type MediaItem =
  | { type: 'image'; url: string; label: string }
  | {
      type: 'video';
      url: string;
      label: string;
      preview?: { url: string; label?: string };
    };

const buildMediaItems = (
  data: ProductModel | null,
  videos: VideosProp
): MediaItem[] => {
  const imageItems: MediaItem[] =
    data?.images?.map((img) => ({
      type: 'image' as const,
      url: img.url,
      label: img.label,
    })) ?? [];

  if (!videos) return imageItems;

  const videoItems: MediaItem[] =
    data?.videos?.map((video) => ({
      type: 'video' as const,
      url: video.url,
      label: video.title ?? '',
      preview: video.preview,
    })) ?? [];

  const position = typeof videos === 'object' ? videos.position : 'last';
  return position === 'first'
    ? [...videoItems, ...imageItems]
    : [...imageItems, ...videoItems];
};

const collectPreloadUrls = (
  data: ProductModel | null,
  videos: VideosProp
): string[] => {
  if (!data) return [];
  const urls: string[] = (data.images ?? []).map((img) => img.url);
  if (videos) {
    (data.videos ?? []).forEach((video) => {
      const previewUrl = getVideoPreviewUrl(video.url, video.preview?.url);
      if (previewUrl) urls.push(previewUrl);
    });
  }
  return urls;
};

const sameMediaUrls = (
  a: ProductModel | null,
  b: ProductModel | null,
  videos: VideosProp
): boolean => {
  if (a === b) return true;
  if (!a || !b) return false;

  const aImages = a.images ?? [];
  const bImages = b.images ?? [];
  if (aImages.length !== bImages.length) return false;
  for (let i = 0; i < aImages.length; i += 1) {
    if (aImages[i].url !== bImages[i].url) return false;
  }

  if (!videos) return true;

  const aVideos = a.videos ?? [];
  const bVideos = b.videos ?? [];
  if (aVideos.length !== bVideos.length) return false;
  for (let i = 0; i < aVideos.length; i += 1) {
    if (aVideos[i].url !== bVideos[i].url) return false;
    // Mirror collectPreloadUrls: a video preview thumbnail change should
    // also trigger the buffered swap, not the fast path.
    const aPreview = getVideoPreviewUrl(
      aVideos[i].url,
      aVideos[i].preview?.url
    );
    const bPreview = getVideoPreviewUrl(
      bVideos[i].url,
      bVideos[i].preview?.url
    );
    if (aPreview !== bPreview) return false;
  }
  return true;
};

const prefersReducedMotion = (): boolean =>
  typeof window !== 'undefined' &&
  typeof window.matchMedia === 'function' &&
  window.matchMedia('(prefers-reduced-motion: reduce)').matches;

interface GalleryContentArgs {
  data: ProductModel | null;
  videos: VideosProp;
  imageParams?: ResolveImageUrlOptions;
  thumbnailParams?: ResolveImageUrlOptions;
  zoom: ProductGalleryProps['zoom'];
  slots: ProductGalleryProps['slots'];
  ImagesLabel?: string;
  onZoom?: (key: number) => void;
}

const useGalleryContent = ({
  data,
  videos,
  imageParams,
  thumbnailParams,
  zoom,
  slots,
  ImagesLabel,
  onZoom,
}: GalleryContentArgs) => {
  const defaultSlotContext: DefaultSlotContext = useMemo(
    () => ({ data }),
    [data]
  );

  const mediaItems = useMemo(
    () => buildMediaItems(data, videos),
    [data, videos]
  );

  const galleryItems = useMemo(
    () =>
      mediaItems.length > 0 ? (
        mediaItems.map((item, key) => {
          const Item = ({ ...itemProps }) => {
            const defaultProps = {
              title: item.label,
              src: item.url,
              alt: ImagesLabel?.replace('{product}', item.label)
                .replace('{key}', String(key + 1))
                .replace('{total}', String(mediaItems.length)),

              // TODO: change width/height for image aspect ratio
              // pending https://jira.corp.adobe.com/browse/DATA-5122
              width: imageParams?.width ?? 960,
              height: imageParams?.height ?? 1191,
              params: imageParams ?? { width: 960 },
              loading: key === 0 ? 'eager' : 'lazy',
              ...itemProps,
            } as const;

            const previewUrl =
              item.type === 'video'
                ? getVideoPreviewUrl(item.url, item.preview?.url)
                : undefined;

            return (
              <Slot
                name="CarouselMainImage"
                slot={slots?.CarouselMainImage}
                context={{
                  ...defaultSlotContext,
                  defaultImageProps: defaultProps,
                  mediaType: item.type,
                  previewUrl,
                }}
              >
                {item.type === 'video' ? (
                  isDirectVideoFile(item.url) ? (
                    <video
                      className="pdp-product-gallery__video"
                      controls
                      preload="metadata"
                      poster={previewUrl}
                      width={imageParams?.width ?? 960}
                      height={imageParams?.height ?? 1191}
                    >
                      <source
                        src={item.url}
                        type={getVideoMimeType(item.url)}
                      />
                      Your browser does not support the video tag.
                    </video>
                  ) : (
                    <iframe
                      className="pdp-product-gallery__video-iframe"
                      src={getEmbedUrl(item.url)}
                      title={item.label || 'Product video'}
                      width={imageParams?.width ?? 960}
                      height={imageParams?.height ?? 1191}
                      loading="lazy"
                      allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                      allowFullScreen
                    />
                  )
                ) : (
                  <Image {...defaultProps} />
                )}
              </Slot>
            );
          };

          return zoom && item.type === 'image' ? (
            <Zoom
              key={item.url}
              closeButton={typeof zoom === 'object' ? zoom.closeButton : false}
            >
              <Item />
            </Zoom>
          ) : (
            <Item key={item.url} onClick={() => onZoom?.(key)} />
          );
        })
      ) : (
        <img
          key="pleaceholder"
          src="data:image/gif;base64,R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7"
          className="pdp-product-gallery__images__placeholder"
          width={imageParams?.width ?? 960}
          height={imageParams?.height ?? 1191}
          aria-hidden
        />
      ),
    [
      ImagesLabel,
      mediaItems,
      imageParams,
      zoom,
      defaultSlotContext,
      slots?.CarouselMainImage,
      onZoom,
    ]
  );

  const thumbnails = useMemo(() => {
    return mediaItems.length > 0 ? (
      mediaItems.map((item, key) => {
        const defaultProps = {
          title: item.label,
          src: item.url,
          alt: ImagesLabel?.replace('{product}', item.label)
            .replace('{key}', String(key + 1))
            .replace('{total}', String(mediaItems.length)),

          // TODO: change width/height for image aspect ratio
          // pending https://jira.corp.adobe.com/browse/DATA-5122
          width: thumbnailParams?.width ?? 200,
          height: thumbnailParams?.height ?? 248,
          params: thumbnailParams ?? { width: 200 },
          loading: 'lazy',
        } as const;

        const previewUrl =
          item.type === 'video'
            ? getVideoPreviewUrl(item.url, item.preview?.url)
            : undefined;

        return (
          <Slot
            key={item.url}
            name="CarouselThumbnail"
            slotTag="span"
            contentTag="span"
            slot={slots?.CarouselThumbnail}
            context={{
              ...defaultSlotContext,
              defaultImageProps: defaultProps,
              mediaType: item.type,
              previewUrl,
            }}
          >
            {item.type === 'video' ? (
              <span
                className="pdp-product-gallery__video-thumbnail"
                role="img"
                aria-label={`Play video: ${item.label || 'Product video'}`}
              >
                {previewUrl ? (
                  <img
                    src={previewUrl}
                    alt=""
                    width={thumbnailParams?.width ?? 200}
                    height={thumbnailParams?.height ?? 248}
                    loading="lazy"
                    aria-hidden="true"
                  />
                ) : (
                  <span
                    className="pdp-product-gallery__video-thumbnail-placeholder"
                    style={{
                      width: thumbnailParams?.width ?? 200,
                      height: thumbnailParams?.height ?? 248,
                    }}
                    aria-hidden="true"
                  />
                )}
                <span
                  className="pdp-product-gallery__video-icon"
                  aria-hidden="true"
                >
                  ▶
                </span>
              </span>
            ) : (
              <Image {...defaultProps} />
            )}
          </Slot>
        );
      })
    ) : (
      <img
        key="pleaceholder"
        src="data:image/gif;base64,R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7"
        className="pdp-product-gallery__thumbnail__placeholder"
        width={thumbnailParams?.width ?? 200}
        height={thumbnailParams?.height ?? 248}
        aria-hidden
      />
    );
  }, [
    ImagesLabel,
    mediaItems,
    thumbnailParams,
    defaultSlotContext,
    slots?.CarouselThumbnail,
  ]);

  return { mediaItems, galleryItems, thumbnails };
};

export const ProductGallery: Container<
  ProductGalleryProps,
  ProductModel | null
> = ({
  initialData = null,
  scope,
  controls = 'dots',
  loop = true,
  peak = false,
  gap = null,
  arrows = true,
  arrowsOnMainImage = false,
  zoom = false,
  videos = false,
  imageParams,
  thumbnailParams,
  children,
  slots,
  ...props
}) => {
  const ImagesLabel = useText('PDP.Product.Image.label').label;

  const [displayedData, setDisplayedData] = useState<ProductModel | null>(
    initialData
  );
  const [pendingData, setPendingData] = useState<ProductModel | null>(null);
  const [entering, setEntering] = useState(false);
  const [zoomTo, setZoomTo] = useState<number | null>(null);

  const displayedRef = useRef<ProductModel | null>(initialData);
  useEffect(() => {
    displayedRef.current = displayedData;
  }, [displayedData]);

  // videosRef avoids re-subscribing the event listener when a consumer passes
  // an inline object for `videos` (a fresh reference on every parent render).
  const videosRef = useRef(videos);
  videosRef.current = videos;

  useEffect(() => {
    const dataEvent = events.on(
      'pdp/data',
      (newData: ProductModel | null) => {
        if (!newData) {
          setDisplayedData(null);
          setPendingData(null);
          setEntering(false);
          return;
        }

        if (sameMediaUrls(displayedRef.current, newData, videosRef.current)) {
          // Same media set — fast path, skip buffering and crossfade.
          setDisplayedData(newData);
          setPendingData(null);
          setEntering(false);
          return;
        }

        setPendingData(newData);
        setEntering(false);
      },
      { scope }
    );
    return () => {
      dataEvent?.off();
    };
  }, [scope]);

  const pendingUrls = useMemo(
    () => collectPreloadUrls(pendingData, videos),
    [pendingData, videos]
  );

  const { ready: pendingReady } = usePreloadImages(pendingUrls, {
    enabled: !!pendingData,
  });

  useEffect(() => {
    if (!pendingData || !pendingReady) return undefined;

    const promote = () => {
      setDisplayedData(pendingData);
      setPendingData(null);
      setEntering(false);
    };

    if (prefersReducedMotion()) {
      promote();
      return undefined;
    }

    // Mount pending layer in opacity:0, flip to 1 on the next frame so the
    // browser commits the initial style before the transition starts.
    const raf = window.requestAnimationFrame(() => setEntering(true));
    const timer = window.setTimeout(promote, CROSSFADE_MS + 50);

    return () => {
      window.cancelAnimationFrame(raf);
      window.clearTimeout(timer);
    };
  }, [pendingReady, pendingData]);

  const { mediaItems, galleryItems, thumbnails } = useGalleryContent({
    data: displayedData,
    videos,
    imageParams,
    thumbnailParams,
    zoom,
    slots,
    ImagesLabel,
    onZoom: setZoomTo,
  });

  const pendingContent = useGalleryContent({
    data: pendingData,
    videos,
    imageParams,
    thumbnailParams,
    zoom,
    slots,
    ImagesLabel,
    // No onZoom: pending layer is non-interactive.
  });

  if (!displayedData) return null;

  const stackClassName = ['pdp-product-gallery__stack', props.className]
    .filter(Boolean)
    .join(' ');

  const pendingLayerClassName = [
    'pdp-product-gallery__layer',
    'pdp-product-gallery__layer--pending',
    entering ? 'pdp-product-gallery__layer--entering' : '',
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <div {...props} className={stackClassName}>
      <div className="pdp-product-gallery__layer">
        <Carousel
          arrows={!!mediaItems.length && arrows}
          arrowsOnMainImage={arrowsOnMainImage}
          controls={mediaItems.length ? controls : undefined}
          loop={loop && !!mediaItems.length}
          peak={!!mediaItems.length && peak}
          gap={gap}
          defaultIndex={zoomTo || 0}
          thumbnails={thumbnails}
        >
          {galleryItems}
        </Carousel>
      </div>

      {pendingData ? (
        <div className={pendingLayerClassName} aria-hidden="true">
          <Carousel
            arrows={!!pendingContent.mediaItems.length && arrows}
            arrowsOnMainImage={arrowsOnMainImage}
            controls={pendingContent.mediaItems.length ? controls : undefined}
            loop={loop && !!pendingContent.mediaItems.length}
            peak={!!pendingContent.mediaItems.length && peak}
            gap={gap}
            defaultIndex={0}
            thumbnails={pendingContent.thumbnails}
          >
            {pendingContent.galleryItems}
          </Carousel>
        </div>
      ) : null}

      {/* Zoom Overlay (always uses displayed data) */}
      {zoomTo === null ? null : (
        <Overlay onClose={() => setZoomTo(null)} centered>
          <Carousel
            arrows={!!mediaItems.length}
            width="100%"
            height="100%"
            defaultIndex={zoomTo}
            loop={loop && !!mediaItems.length}
            controls="dots"
            isZoomed
          >
            {galleryItems}
          </Carousel>
        </Overlay>
      )}
    </div>
  );
};

ProductGallery.getInitialData = getFetchedProductData;
